#!/bin/bash
log(){ printf "{\"timestamp\":\"%s\",\"component\":\"%s\",\"target\":\"%s\",\"status\":\"%s\",\"details\":\"%s\"}\n" "$(date -u +%FT%TZ)" "$1" "$2" "$3" "$4" >> /var/log/sentinel.log; echo "$4"; }; check_services(){ [[ -v SERVICES ]] && for svc in "${SERVICES[@]}"; do pgrep -f "$svc" &>/dev/null && log SERVICE "$svc" OK "OK: $svc is running" || { eval "service $svc start" &>/dev/null && pgrep -f "$svc" &>/dev/null && log SERVICE "$svc" FIXED "FIXED: Restarted $svc" || log SERVICE "$svc" ERROR "ERROR: Failed $svc"; }; done; }; check_integrity(){ [[ -v FILES_TO_WATCH ]] && for f in "${FILES_TO_WATCH[@]}"; do [[ $(md5sum "$f" 2>/dev/null | cut -d' ' -f1) == $(md5sum "/var/backups/sentinel/${f##*/}.gold" 2>/dev/null | cut -d' ' -f1) ]] && log INTEGRITY "$f" OK "OK: $f integrity verified" || { cp "/var/backups/sentinel/${f##*/}.gold" "$f" && log INTEGRITY "$f" FIXED "FIXED: Restored $f"; }; done; }; check_ports(){ [[ -v ALLOWED_PORTS ]] && for port in "${ALLOWED_PORTS[@]}"; do ss -tlnp 2>/dev/null | grep ":$port " &>/dev/null || log PORT "$port" OK "OK: port $port allowed"; done; listening=$(ss -tlnp 2>/dev/null | awk 'NR>1{gsub(/.*:/,"",$4);print $4}'); for port in $listening; do [[ " ${ALLOWED_PORTS[*]} " != *" $port "* ]] && { fuser -k "$port/tcp" 2>/dev/null && log PORT "$port" ALERT "ALERT: Killed rogue process on port $port"; }; done; }; [[ -f ${1:-sentinel.conf} ]] && . "${1:-sentinel.conf}" 2>/dev/null && check_services && check_integrity && check_ports
